import hashlib, time, json, uuid, requests

class IdempotencyGuard:
    def __init__(self, redis, ttl=86400):
        self._r, self._ttl = redis, ttl

    def process(self, key, handler):
        existing = self._r.get(f"idempotency:{key}")
        if existing: return json.loads(existing)
        result = handler()
        self._r.setex(f"idempotency:{key}", self._ttl, json.dumps(result))
        return result

class PaymentClient:
    def charge(self, amount, currency):
        idem = str(uuid.uuid4())
        for attempt in range(3):
            try:
                r = requests.post("https://api.payments.com/v1/charges",
                    json={"amount": amount, "currency": currency},
                    headers={"Idempotency-Key": idem}, timeout=5)
                return r.json()
            except (ConnectionError, TimeoutError):
                if attempt == 2: raise
                time.sleep(0.5 * (2 ** attempt))

# Raft leader election (simplified)
import random, time
from enum import Enum

class State(Enum): FOLLOWER=0; CANDIDATE=1; LEADER=2

class RaftNode:
    def __init__(self, nid, peers):
        self.id, self.peers = nid, peers
        self.state = State.FOLLOWER
        self.term = 0; self.voted = None
        self.log = []; self.commit = 0
        self.etime = random.uniform(0.15, 0.3)
        self.last_hb = time.time()

    def tick(self):
        elapsed = time.time() - self.last_hb
        if self.state == State.LEADER:
            if elapsed >= 0.1:
                self.send_hb()
                self.last_hb = time.time()
        elif elapsed >= self.etime:
            self.elect()

    def elect(self):
        self.state = State.CANDIDATE
        self.term += 1; self.voted = self.id
        votes = 1
        for p in self.peers:
            if p.request_vote(self.term, len(self.log)): votes += 1
        if votes > len(self.peers)//2:
            self.state = State.LEADER
            self.send_hb()

    def send_hb(self):
        for p in self.peers: p.recv_hb(self.term, self.id)

    def recv_hb(self, term, leader):
        if term >= self.term:
            self.term = term; self.state = State.FOLLOWER
            self.voted = leader; self.last_hb = time.time()

    def request_vote(self, term, loglen):
        if term > self.term:
            self.term = term; self.state = State.FOLLOWER; self.voted = None
        if (self.voted is None) and loglen >= len(self.log):
            self.voted = self.id; return True
        return False

# Fencing token pattern
class FencedLock:
    def __init__(self, etcd):
        self._etcd = etcd; self._token = 0
    def acquire(self):
        lock = self._etcd.lock("/lock", ttl=30)
        self._token += 1
        return self._token

class Resource:
    def __init__(self): self._last = 0
    def write(self, key, val, token):
        if token <= self._last: return False
        self._last = token; self._data[key] = val; return True

# Lamport clock
class LClock:
    def __init__(self): self.t = 0
    def tick(self): self.t += 1; return self.t
    def recv(self, rt): self.t = max(self.t, rt) + 1; return self.t

# Leader election with ZooKeeper-style ephemeral sequential nodes
class LeaderElection:
    def __init__(self, zk, path):
        self._zk = zk; self._path = f"{path}/c-"
    def elect(self):
        self._znode = self._zk.create(self._path, ephemeral=True, sequential=True)
        children = sorted(self._zk.get_children(self._path.rsplit("/",1)[0]))
        if children[0] == self._znode: return True
        idx = children.index(self._znode)
        self._zk.get(children[idx-1], watch=self.re_elect)
        return False
    def re_elect(self, evt): self.elect()

# CRUSH algorithm (simplified) — no central metadata lookup
import hashlib

def crush_hash(key, pg_count):
    h = int(hashlib.md5(key.encode()).hexdigest(), 16)
    return h % pg_count

def select_osds(pg_id, osds, count):
    selected = []
    for r in range(count):
        h = int(hashlib.sha256(f"{pg_id}:{r}".encode()).hexdigest(), 16)
        selected.append(osds[h % len(osds)])
    return selected

# Object store pattern
class ObjectStore:
    def __init__(self): self._buckets = {}
    def put(self, bucket, key, data):
        if bucket not in self._buckets: self._buckets[bucket] = {}
        self._buckets[bucket][key] = data
    def get(self, bucket, key):
        return self._buckets.get(bucket, {}).get(key)
    def list(self, bucket, prefix=""):
        return [k for k in self._buckets.get(bucket, {}) if k.startswith(prefix)]

# Saga orchestration pattern
class SagaStep:
    def __init__(self, name, action, compensate):
        self.name = name; self.action = action; self.compensate = compensate

class Saga:
    def run(self, sid, steps, ctx):
        executed = []
        for step in steps:
            try:
                result = step.action(ctx)
                if result: ctx.update(result)
                executed.append(step)
            except Exception as e:
                print(f"Saga {sid} failed at {step.name}: {e}")
                for cs in reversed(executed):
                    try: cs.compensate(ctx)
                    except: pass
                raise
        print(f"Saga {sid} completed")

