# CRDT: G-Counter
class GCounter:
    def __init__(self, nid):
        self.nid = nid; self._counts = {}
    def inc(self): self._counts[self.nid] = self._counts.get(self.nid, 0) + 1
    def val(self): return sum(self._counts.values())
    def merge(self, other):
        for n, c in other._counts.items():
            self._counts[n] = max(self._counts.get(n, 0), c)

# CRDT: OR-Set
class ORSet:
    def __init__(self): self._e = {}  # element -> set of tags
    def add(self, elem, tag):
        if elem not in self._e: self._e[elem] = set()
        self._e[elem].add(tag)
    def remove(self, elem): self._e.pop(elem, None)
    def val(self): return set(self._e.keys())
    def merge(self, other):
        for elem, tags in other._e.items():
            if elem in self._e: self._e[elem].update(tags)
            else: self._e[elem] = tags.copy()

# Quorum store
class QuorumStore:
    def __init__(self, nodes):
        self._nodes = nodes; self.N = len(nodes)
        self.W = self.N//2+1; self.R = self.N//2+1
    def write(self, key, val):
        return sum(1 for n in self._nodes if n.put(key, val)) >= self.W
    def read(self, key):
        vals = [(n.get(key), n) for n in self._nodes if n.get(key)]
        if len(vals) >= self.R:
            return max(vals, key=lambda x: x[1])[0]
        return None

# Consistent hash ring
import hashlib

class Ring:
    def __init__(self, vnodes=100):
        self._vn = vnodes; self._ring = {}; self._sorted = []
    def _h(self, k): return int(hashlib.md5(k.encode()).hexdigest(), 16)
    def add(self, node):
        for v in range(self._vn):
            h = self._h(f"{node}:{v}")
            self._ring[h] = node
        self._sorted = sorted(self._ring)
    def remove(self, node):
        self._ring = {h:n for h,n in self._ring.items() if n != node}
        self._sorted = sorted(self._ring)
    def get(self, key):
        if not self._ring: return None
        h = self._h(key)
        for rh in self._sorted:
            if rh >= h: return self._ring[rh]
        return self._ring[self._sorted[0]]
    def get_n(self, key, n=3):
        nodes, h = [], self._h(key)
        for rh in self._sorted:
            if rh >= h: node = self._ring[rh]
            else: node = self._ring[rh]
            if node not in nodes: nodes.append(node)
            if len(nodes) >= n: break
        return nodes[:n]

