# Cache stampede prevention
import random, time, threading

class StampedeGuard:
    def __init__(self, redis):
        self._redis = redis; self._locks = {}

    def get_or_compute(self, key, ttl, func, early=0.2):
        rem = self._redis.ttl(key)
        if rem is not None and rem < ttl*early and random.random() < 0.1:
            return self._recompute(key, ttl, func, self._locks.get(key) or threading.Lock())
        cached = self._redis.get(key)
        if cached: return cached
        return self._recompute(key, ttl, func, self._locks.get(key) or threading.Lock())

    def _recompute(self, key, ttl, func, lock):
        with lock:
            val = self._redis.get(key)
            if val: return val
            val = func()
            self._redis.setex(key, ttl, val)
            return val

# Multi-tier caching
class MultiTier:
    def __init__(self, l1, l2, origin, l1_ttl=10, l2_ttl=60):
        self._l1 = l1; self._l2 = l2; self._origin = origin
        self._l1t = l1_ttl; self._l2t = l2_ttl
    def get(self, key):
        val = self._l1.get(key)
        if val: return val
        val = self._l2.get(key)
        if val: self._l1.setex(key, self._l1t, val); return val
        val = self._origin(key)
        self._l2.setex(key, self._l2t, val)
        self._l1.setex(key, self._l1t, val)
        return val

# Scheduling algorithm (simplified K8s scheduler)
from dataclasses import dataclass

@dataclass
class Pod:
    name: str; cpu: float; mem: float; pri: int = 0

@dataclass
class Node:
    name: str; cpu_cap: float; mem_cap: float
    cpu_used: float = 0; mem_used: float = 0
    def cpu_avail(self): return self.cpu_cap - self.cpu_used
    def mem_avail(self): return self.mem_cap - self.mem_used

def feasible(node, pod):
    return node.cpu_avail() >= pod.cpu and node.mem_avail() >= pod.mem

def score(node):
    return ((node.cpu_avail()/node.cpu_cap)+(node.mem_avail()/node.mem_cap))/2 * 10

def schedule(pods, nodes):
    assignments = {}
    for pod in sorted(pods, key=lambda p: p.pri, reverse=True):
        feasible_nodes = [(n, score(n)) for n in nodes if feasible(n, pod)]
        if not feasible_nodes:
            raise RuntimeError(f"No node for {pod.name}")
        chosen = max(feasible_nodes, key=lambda x: x[1])[0]
        chosen.cpu_used += pod.cpu; chosen.mem_used += pod.mem
        assignments[pod.name] = chosen.name
    return assignments

nodes = [Node(f"n{i}", 8, 32000) for i in range(3)]
pods = [Pod("web", 1, 4096, 10), Pod("batch", 4, 8192, 1),
        Pod("batch2", 4, 8192, 1), Pod("web2", 1, 2048, 10)]
res = schedule(pods, nodes)
for p,n in res.items(): print(f"{p:10s} -> {n}")

