# Resilient RPC with retry + circuit breaker
class ResilientRPC:
    def __init__(self, stub, cb):
        self._stub = stub; self._cb = cb
    def call(self, method, req, retries=3):
        for a in range(retries):
            try:
                return self._cb.call(getattr(self._stub, method), req)
            except (TimeoutError, ConnectionError) as e:
                if a == retries-1: raise
                time.sleep(0.1 * (2**a))

# JWT validation middleware
import jwt, time, requests

class JWTValidator:
    def __init__(self, jwks_url, audience, issuer):
        self._jwks_url = jwks_url; self._aud = audience; self._iss = issuer
        self._cache = {}

    def validate(self, token):
        try:
            unv = jwt.decode(token, options={"verify_signature": False})
            key = self._get_key(unv.get("kid"))
            if not key: return None
            return jwt.decode(token, key, algorithms=["RS256"],
                              audience=self._aud, issuer=self._iss)
        except: return None

    def _get_key(self, kid):
        if kid in self._cache:
            k, exp = self._cache[kid]
            if time.time() < exp: return k
        jwks = requests.get(self._jwks_url).json()
        for kd in jwks["keys"]:
            if kd["kid"] == kid:
                from jwt.algorithms import RSAAlgorithm
                key = RSAAlgorithm.from_jwk(json.dumps(kd))
                self._cache[kid] = (key, time.time()+3600)
                return key
        return None

