# Chaos experiment framework
from dataclasses import dataclass
from enum import Enum
import time

class ExpStatus(Enum): RUNNING=0; COMPLETED=1; FAILED=2

@dataclass
class Experiment:
    name: str; target: str; fault: str
    duration: int; blast: str
    hypothesis: dict  # e.g. {"p99_latency_inc": "<500ms"}

class ChaosEngine:
    def __init__(self, metrics): self._m = metrics

    def run(self, exp):
        print(f"Starting {exp.name}")
        baseline = self._m.snapshot()
        try:
            self._inject(exp)
            time.sleep(exp.duration)
            self._rollback(exp)
            post = self._m.snapshot()
            self._verify(exp.hypothesis, baseline, post)
            return ExpStatus.COMPLETED
        except:
            self._rollback(exp)
