# DNS-based GSLB (simplified)
class GSLB:
    def __init__(self, regions):
        self._regions = regions  # {"us-east": {"ips": [...], "health": True}}
    def resolve(self, geo):
        healthy = {r: v for r,v in self._regions.items() if v.get("health", True)}
        if geo in healthy: return healthy[geo]["ips"]
        for r in healthy: return healthy[r]["ips"]
        return []
    def mark_unhealthy(self, region):
        if region in self._regions: self._regions[region]["health"] = False

# CDN cache hierarchy (origin shield)
class OriginShield:
    def __init__(self, l2, origin):
        self._l2 = l2; self._origin = origin
    def get(self, key):
        val = self._l2.get(key)
        if val: return val
        val = self._origin.fetch(key)
        self._l2.set(key, val, ttl=3600)
        return val

class EdgeNode:
    def __init__(self, l1, shield):
        self._l1 = l1; self._shield = shield
    def serve(self, key):
        val = self._l1.get(key)
        if val: return val
        val = self._shield.get(key)
        self._l1.set(key, val, ttl=60)
        return val
